package be.schaubroeck.lpb.rkm.rekenmotor.rsz.rszppo;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AbstractGewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BepaalAardCodeExtensieData;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CodeExtensie;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Rekenwijze;
import be.schaubroeck.lpb.tools.enumtypes.RszppoKategorie;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.temporal.interval.LocalDateInterval;

public class GewoonLoonRszppo extends AbstractGewoonLoon {

    public GewoonLoonRszppo(LoonCodeManager loonCodeManager, LocalDateInterval rekenPeriode) {
        super(loonCodeManager, rekenPeriode);
    }

    public AardKodeExtensie bepaalAardKodeExtensie(SleutelGegevens gegevens) {
        RszppoKategorie categorie = gegevens.getCategorie();
        Hoedanigheid hoedanigheid = gegevens.getHoedanigheid();
        Rekenwijze rekenwijze = gegevens.getRekenWijze();
        return bepaalAardKodeExtensieGewoonLoonRszppo(categorie, hoedanigheid, rekenwijze);
    }

    @Override
    public AardKodeExtensie bepaalAardKodeExtensieGewoonLoonDmfappl(BepaalAardCodeExtensieData bepaalAardCodeExtensieData) {
        throw new MessageException("Dmfappl in rszppo tijdperk mag nooit voorkomen.");
    }

    public AardKodeExtensie bepaalAardKodeExtensieGewoonLoonRszppo(RszppoKategorie categorie, Hoedanigheid hoedanigheid, Rekenwijze rekenwijze) {
        CodeExtensie looncode = CodeExtensie.GEWOON_LOON;

        if (hoedanigheid == Hoedanigheid.WACHTWEDDEN) {
            looncode = CodeExtensie.WACHTWEDDE_RSZPPO;
        } else if (hoedanigheid == Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES && rekenwijze == Rekenwijze.MAAND) {
            if (categorie == RszppoKategorie.N_GESUB_GP) {
                looncode = CodeExtensie.TOEZICHT_VASTBENOEMD_RSZPPO;
            } else if (categorie == RszppoKategorie.OW_NG_PU) {
                looncode = CodeExtensie.TOEZICHT_CONTRACTUEEL_RSZPPO;
            }

        } else if (hoedanigheid == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN && (categorie == RszppoKategorie.GH_C_PR
                || categorie == RszppoKategorie.GH_VRIJG)) {
            looncode = CodeExtensie.GENEESHEER_RSZPPO;
        } else if (hoedanigheid == Hoedanigheid.MANDATARISSEN) {
            looncode = CodeExtensie.MANDATARIS;
        } else if (hoedanigheid == Hoedanigheid.MANDATARISSEN_GEPENSIOENEERD || hoedanigheid == Hoedanigheid.WERKNEMERS_GEPENSIOENEERD) {
            looncode = CodeExtensie.PENSIOEN;
        }
        return getVergoedingAke(AkeTijdperk.RSZPPO, looncode);
    }
}
